  "inputSourceName": "project/contracts/TCF_NFT.sol",
  "devdoc": {
    "kind": "dev",
    "methods": {
      "addSupportedToken(address)": {
        "details": "添加支持的代币地址列表（原生代币不需要传入地址）。构造函数中已经添加了原生代币TC。 如果项目只支持TC，则不需要调用这个函数。",
        "params": {
          "_tokenAddress": "代币合约地址"
        }
      },
      "balanceOfBatch(address[],uint256[])": {
        "details": "See {IERC1155-balanceOfBatch}.没有实现 Requirements: - `accounts` and `ids` must have the same length."
      },
      "changeNFTPrice(uint256,address,uint256)": {
        "details": "修改单个NFT价格",
        "params": {
          "amount": "新价格",
          "tokenAddress": "支付代币地址；原生代币传入address(0)",
          "tokenId": "NFT类型/ID（0-5）"
        }
      },
      "checkInitPricesParams((address,uint256)[2][6])": {
        "details": "初始化价格参数检查：长度、代币是否在支持列表内等。",
        "params": {
          "prices": "6种NFT的价格参数（每种NFT包含 supportedTokenAmount 个价格项）"
        },
        "returns": {
          "_0": "错误码/错误信息；成功时为空字符串"
        }
      },
      "getNFTPrice(uint256,address)": {
        "details": "获取某个NFT在某种支付方式下的价格。",
        "params": {
          "_tokenAddress": "支付代币地址；原生代币传入address(0)",
          "tokenId": "NFT类型/ID（0-5）"
        },
        "returns": {
          "_0": "errorMessage 错误码/错误信息；成功时为空字符串",
          "_1": "price 价格；当errorMessage非空时为0"
        }
      },
      "getOptimalParent(address,address)": {
        "details": "从 recommender 出发：      1) 对当前节点比较左右子树价值（空子树视为 0），优先走价值更小的一侧（相等则优先 left）。      2) 若优先侧为空，说明当前节点在该侧有空位；若当前节点买过 NFT，则返回该节点作为父节点。      3) 若当前节点没有买过 NFT，则该节点不能作为父节点，需要继续查找；         若这条路径最终找不到可用父节点，则回退尝试另一侧（等价于排除上一条路径）。      4) 整个查找过程中会跳过 excludeNode（通常是当前要插入的节点），避免推荐自己。",
        "params": {
          "excludeNode": "在推荐父节点时排除掉这个节点（通常是当前要插入的节点），避免出现推荐自己作为父节点的情况",
          "recommender": "推荐人地址（必须已在树中）"
        },
        "returns": {
          "isLeftBranch": "推荐在 parent 下应选择的分支：true=left，false=right",
          "parent": "推荐得到的最终父节点地址"
        }
      },
      "initPrice((address,uint256)[2][6])": {
        "details": "初始化价格.TC代币的地址设为0",
        "params": {
          "prices": "6种NFT,每中NFT的三类价格"
        }
      },
      "initRoot(address)": {
        "params": {
          "rootAddress": "根节点地址"
        }
      },
      "insert(address,address,bool)": {
        "details": "约束：  - parent 必须已存在。  - recommender 必须已存在。  - 若 recommender 推荐该 node，则 parent 必须在 recommender 的子树内（含 recommender 本人）。",
        "params": {
          "isLeft": "true=插入为 parent.left；false=插入为 parent.right。  如果isLeft未true，优先放在父节点的左子树下，如果左子树下有节点，则放在右子树下；反之亦然。  我什么存在：因为如果使用推荐节点，推荐函数将返回一个父节点和isLeft参数，这样插入函数就可以直接使用。",
          "parent": "父节点地址",
          "recommender": "推荐人地址（必须是当前树中的某个地址）"
        }
      },
      "isApprovedForAll(address,address)": {
        "details": "See {IERC1155-isApprovedForAll}."
      },
      "owner()": {
        "details": "Returns the address of the current owner."
      },
      "paused()": {
        "details": "Returns true if the contract is paused, and false otherwise."
      },
      "renounceOwnership()": {
        "details": "Leaves the contract without owner. It will not be possible to call `onlyOwner` functions. Can only be called by the current owner. NOTE: Renouncing ownership will leave the contract without an owner, thereby disabling any functionality that is only available to the owner."
      },
      "safeBatchTransferFrom(address,address,uint256[],uint256[],bytes)": {
        "details": "See {IERC1155-safeBatchTransferFrom}."
      },
      "safeTransferFrom(address,address,uint256,uint256,bytes)": {
        "details": "See {IERC1155-safeTransferFrom}.没有实现"
      },
      "setApprovalForAll(address,bool)": {
        "details": "See {IERC1155-setApprovalForAll}."
      },
      "setBaseURI(bytes[6])": {
        "details": "Sets `baseURI` as the `_baseURI` for all tokens Only callable by the owner.可以被设置多次"
      },
      "supportsInterface(bytes4)": {
        "details": "See {IERC165-supportsInterface}."
      },
      "totalTreeWorth()": {
        "details": "注意：树很大时可能消耗较多 gas（即使 view 调用也有计算开销）。"
      },
      "transferOwnership(address)": {
        "details": "Transfers ownership of the contract to a new account (`newOwner`). Can only be called by the current owner."
      }
    },
    "version": 1
  },
